    @Override // com.genoma.plus.dao.presupuesto.EjecucionPresupuestalDAO
    public String libroPresupuestalIngreso(String x, String idPeriodo, String idEncabezado) {
        String str = "select * from tmp_rubros_def_" + x + "";
        String sql = "WITH rubros_definitivos AS (\nSELECT * FROM tmp_rubros_def_" + x + "\nWHERE TipoRubro='I'\n)\n, cc_tercero_w AS (\nSELECT\n  `g_empresa`.`Id`                       AS `Id`,\n  `g_empresa`.`Apellido1`                AS `Apellido1`,\n  `g_empresa`.`Apellido2`                AS `Apellido2`,\n  `g_empresa`.`Nombre1`                  AS `Nombre1`,\n  `g_empresa`.`Nombre2`                  AS `Nombre2`,\n  IF(`g_empresa`.`Id_TipoIdentificacion` = _latin1'NI',`g_empresa`.`Nbre`,_latin1'') AS `RazonSocial`,\n  `g_empresa`.`Id_TipoIdentificacion`    AS `Id_TipoIdentificacion`,\n  `g_tipoidentificacion`.`EsContable`    AS `EsContable`,\n  `g_tipoidentificacion`.`Id_Dian`       AS `Id_Dian`,\n  `g_empresa`.`No_identificacion`        AS `No_identificacion`,\n  `g_empresa`.`Dig_Verificacion`         AS `Dig_Verificacion`,\n  `g_municipio`.`Id`                     AS `CodMunicipio`,\n  `g_municipio`.`Nbre`                   AS `NMunicipio`,\n  `g_departamento`.`Id`                  AS `CodDepartamento`,\n  `g_departamento`.`Nbre`                AS `NDepartamento`,\n  `g_departamento`.`CodPais`             AS `CodPais`,\n  `g_empresa`.`Direccion`                AS `Direccion`,\n  `g_empresa`.`Tel_Numero`               AS `Tel_Numero`,\n  `g_empresa`.`Fax`                      AS `Fax`,\n  `g_empresa`.`Correo`                   AS `Correo`,\n  `g_empresa`.`EsManejoC`                AS `EsManejoC`,\n  `g_empresa`.`EsPlaboratorio`           AS `Laboratorio`,\n  `g_empresa`.`GRetencion`               AS `GRetencion`,\n  `g_empresa`.`Eps`                      AS `EsEps`,\n  `g_empresa`.`VCompraP`                 AS `VCompraP`,\n  `g_empresa`.`UFMovimientoC`            AS `FUMovimiento`,\n  `g_empresa`.`ActivoC`                  AS `ActivoC`,\n  `g_empresa`.`Estado`                   AS `Estado`,\n  `g_empresa`.`EsMInventario`            AS `EsMInventario`,\n  `g_empresa`.`TipoPersona`              AS `TipoPersona`,\n  `g_empresa`.`FacTInterna`              AS `FacTInterna`,\n  `g_empresa`.`Fecha_Ingreso`            AS `Fecha_Ingreso`,\n  `g_empresa`.`EsNomina`                 AS `EsNomina`,\n  `cc_tipo_clasificacion_tercero`.`Nbre` AS `Clasificacion`,\n  IF(`g_empresa`.`Id_TipoIdentificacion` = _latin1'NI',`g_empresa`.`Nbre`,CONCAT(`g_empresa`.`Apellido1`,_latin1' ',`g_empresa`.`Apellido2`,_latin1' ',`g_empresa`.`Nombre1`,_latin1' ',`g_empresa`.`Nombre2`)) AS `RazonSocialCompleta`,\n  IF(`g_empresa`.`Dig_Verificacion` = _latin1'',CONCAT(`g_empresa`.`Id_TipoIdentificacion`,_latin1' ',`g_empresa`.`No_identificacion`),CONCAT(IF(`g_empresa`.`Id_TipoIdentificacion` = _latin1'NI',_latin1'NIT',`g_empresa`.`Id_TipoIdentificacion`),_latin1' ',`g_empresa`.`No_identificacion`,_latin1'-',`g_empresa`.`Dig_Verificacion`)) AS `TDCompleto`,\n  IF(`g_empresa`.`Dig_Verificacion` = _latin1'',CONCAT(`g_empresa`.`Id_TipoIdentificacion`,_latin1' ',`g_empresa`.`No_identificacion`),CONCAT(`g_empresa`.`No_identificacion`,_latin1'-',`g_empresa`.`Dig_Verificacion`)) AS `TDCompleto1`,\n  IF(`g_empresa`.`Dig_Verificacion` = _latin1'',`g_empresa`.`No_identificacion`,CONCAT(`g_empresa`.`No_identificacion`,_latin1'-',`g_empresa`.`Dig_Verificacion`)) AS `TDCompleto2`\nFROM ((((`g_empresa`\n      JOIN `g_municipio`\n        ON (`g_empresa`.`Id_Municipio` = `g_municipio`.`Id`))\n     JOIN `g_departamento`\n       ON (`g_municipio`.`Id_Dpto` = `g_departamento`.`Id`))\n    JOIN `g_tipoidentificacion`\n      ON (`g_tipoidentificacion`.`Id` = `g_empresa`.`Id_TipoIdentificacion`))\n   JOIN `cc_tipo_clasificacion_tercero`\n     ON (`cc_tipo_clasificacion_tercero`.`Id` = `g_empresa`.`Id_ClasificacionT`))\nORDER BY `g_empresa`.`Nbre`\n\n)\n\n, set_reconocimiento_actual AS (\nSELECT\n    DATE_FORMAT(`pp_movimiento`.`FechaD`,'%d-%m-%Y') AS Fecha\t\n    , DATE_FORMAT(`pp_movimiento`.`FechaD`,'%d') AS Dia\n    , DATE_FORMAT(`pp_movimiento`.`FechaD`,'%m') AS Mes\n    , IF(`pp_movimiento`.`NoConcecutivo`=0,pp_detalle_movimiento.`Id`,`pp_movimiento`.`NoConcecutivo`) AS `Numero`\n    , IFNULL(`pp_tipo_documentos`.`Prefijo`,'') AS `Clase`\n    , IF(pp_detalle_movimiento.`Tipo`=0,'2','1') AS Signo\n    , pp_detalle_movimiento.`Valor`\n    , `pp_movimiento`.`DatoResolucion` AS TipoDocSoporte\n    , `pp_movimiento`.`DatoResolucion` AS NumeroDocSoporte\n    , IF(cc_tercero_w.`Id_TipoIdentificacion`='CC',cc_tercero_w.`No_identificacion`,CONCAT(cc_tercero_w.`No_identificacion`,IF(cc_tercero_w.`Dig_Verificacion`<>'','-',''), cc_tercero_w.`Dig_Verificacion`)) identificacion\n    , cc_tercero_w.`RazonSocialCompleta`\n    , pp_detalle_movimiento.`Id_Rubro`\n    ,pp_movimiento.`Observacion`\n  FROM\n    `pp_detalle_movimiento`\n    INNER JOIN `pp_movimiento` \n        ON (`pp_detalle_movimiento`.`Id_Movimiento` = `pp_movimiento`.`Id`)\n    INNER JOIN `pp_tipo_documentos` \n        ON (`pp_movimiento`.`Id_TipoDoc` = `pp_tipo_documentos`.`Id`)\n    INNER JOIN cc_tercero_w \n        ON (`pp_detalle_movimiento`.`Id_Tercero` = cc_tercero_w.`Id`)\nWHERE (`pp_tipo_documentos`.`Id_ClaseDoc` IN(2)\n    AND `pp_detalle_movimiento`.`Estado` =1 AND pp_movimiento.`Id_Periodo`=" + idPeriodo + " AND pp_detalle_movimiento.idEncabezado='" + idEncabezado + "')\nORDER BY `pp_tipo_documentos`.`Id_ClaseDoc` ASC,`pp_movimiento`.`FechaD` DESC\n)\n\n,w_ips AS (SELECT\n  IF(`g_ips`.`Id_TipoIdentificacion` = _latin1'NI',_latin1'NIT',`g_ips`.`Id_TipoIdentificacion`) AS `TipoIdEmpresa`,\n  `g_ips`.`Identificacion`        AS `NIEmpresa`,\n  `g_ips`.`DigitoVerificacion`    AS `DVempresa`,\n  `g_ips`.`Nbre`                  AS `NEmpresa`,\n  `g_ips`.`Direccion`             AS `Direccion`,\n  `g_ips`.`Direccion2`            AS `Direccion2`,\n  `g_ips`.`Eslogan`               AS `Eslogan`,\n  `g_ips`.`Telefono`              AS `Telefono`,\n  `g_ips`.`Fax`                   AS `Fax`,\n  `g_ips`.`Correo`                AS `Correo`,\n  `g_ips`.`Web`                   AS `Web`,\n  `g_ips`.`Administrador`         AS `Administrador`,\n  `g_ips`.`UrlFA`                 AS `UrlFA`,\n  `g_ips`.`Gerente`               AS `Gerente`,\n  `g_ips`.`UrlFG`                 AS `UrlFG`,\n  `g_ips`.`Presidente`            AS `Presidente`,\n  `g_ips`.`UrlFV`                 AS `UrlFV`,\n  `g_ips`.`Contadora`             AS `Contadora`,\n  `g_ips`.`UrlCd`                 AS `UrlCd`,\n  SUBSTR(`g_municipio`.`Id`,3,4)  AS `CodMunicipio`,\n  `g_municipio`.`Nbre`            AS `NMunicipio`,\n  `g_departamento`.`Id`           AS `CodDepartamento`,\n  `g_departamento`.`Nbre`         AS `NDepartamento`,\n  `g_departamento`.`CodPais`      AS `CodPais`,\n  `g_ips`.`TopeCompraA`           AS `TopeCompraA`,\n  `g_ips`.`TopeCompraG`           AS `TopeCompraG`,\n  `g_ips`.`TopeCompraV`           AS `TopeCompraV`,\n  `g_ips`.`NotaAnticipos`         AS `NotaAnticipos`,\n  IF(`g_ips`.`UrlLogo` = '',NULL,`g_ips`.`UrlLogo`) AS `Logo`,\n  IF(`g_ips`.`UrlLogoC` = '',NULL,`g_ips`.`UrlLogoC`) AS `LogoC`,\n  `g_ips`.`PiePaginaCitas`        AS `PiePaginaCitas`,\n  `g_ips`.`PiePaginaCitas1`       AS `PiePaginaCitas1`,\n  IF(`g_ips`.`UrlLogoSuperS` = '',NULL,`g_ips`.`UrlLogoSuperS`) AS `UrlLogoSuperS`,\n  `g_ips`.`ResolucionDian`        AS `ResolucionDian`,\n  IF(`g_ips`.`DigitoVerificacion` = _latin1'',`g_ips`.`Identificacion`,CONCAT(`g_ips`.`Identificacion`,_latin1'-',`g_ips`.`DigitoVerificacion`)) AS `IdConcatenado`,\n  `g_ips`.`Id_TipoIdentificacion` AS `TipoIdNormal`,\n  `g_ips`.`CodigoOrganismo`       AS `CodigoOrganismo`,\n  `g_ips`.`PiePagina1`            AS `PiePagina1`,\n  `g_ips`.`PiePagina2`            AS `PiePagina2`,\n  `g_ips`.`Id`                    AS `Id`,\n  `g_ips`.`Id_gempresa`           AS `Id_gempresa`,\n  `g_ips`.`LCertificacionSoat`    AS `LCertificacionSoat`,\n  `g_ips`.`LOrdenSalida`          AS `LOrdenSalida`,\n  `g_ips`.`prefijoReportes`       AS `prefijoReportes`\nFROM ((`g_ips`\n    JOIN `g_municipio`\n      ON (`g_ips`.`Id_Municipio` = `g_municipio`.`Id`))\n   JOIN `g_departamento`\n     ON (`g_municipio`.`Id_Dpto` = `g_departamento`.`Id`)))\n\n\nSELECT * FROM  w_ips, set_reconocimiento_actual rec\nINNER JOIN rubros_definitivos pres\nON rec.Id_Rubro=pres.Id\nORDER BY rec.Id_Rubro";
        return sql;
    }

    @Override // com.genoma.plus.dao.presupuesto.EjecucionPresupuestalDAO
    public String libroPresupuestalGastos(String x, String idPeriodo, String idEncabezado) {
        String str = "select * from tmp_rubros_def_" + x + "";
        String sql = "WITH rubros_definitivos AS (\nSELECT * FROM tmp_rubros_def_" + x + "\nWHERE TipoRubro='G'\n)\n, cc_tercero_w AS (\nSELECT\n  `g_empresa`.`Id`                       AS `Id`,\n  `g_empresa`.`Apellido1`                AS `Apellido1`,\n  `g_empresa`.`Apellido2`                AS `Apellido2`,\n  `g_empresa`.`Nombre1`                  AS `Nombre1`,\n  `g_empresa`.`Nombre2`                  AS `Nombre2`,\n  IF(`g_empresa`.`Id_TipoIdentificacion` = _latin1'NI',`g_empresa`.`Nbre`,_latin1'') AS `RazonSocial`,\n  `g_empresa`.`Id_TipoIdentificacion`    AS `Id_TipoIdentificacion`,\n  `g_tipoidentificacion`.`EsContable`    AS `EsContable`,\n  `g_tipoidentificacion`.`Id_Dian`       AS `Id_Dian`,\n  `g_empresa`.`No_identificacion`        AS `No_identificacion`,\n  `g_empresa`.`Dig_Verificacion`         AS `Dig_Verificacion`,\n  `g_municipio`.`Id`                     AS `CodMunicipio`,\n  `g_municipio`.`Nbre`                   AS `NMunicipio`,\n  `g_departamento`.`Id`                  AS `CodDepartamento`,\n  `g_departamento`.`Nbre`                AS `NDepartamento`,\n  `g_departamento`.`CodPais`             AS `CodPais`,\n  `g_empresa`.`Direccion`                AS `Direccion`,\n  `g_empresa`.`Tel_Numero`               AS `Tel_Numero`,\n  `g_empresa`.`Fax`                      AS `Fax`,\n  `g_empresa`.`Correo`                   AS `Correo`,\n  `g_empresa`.`EsManejoC`                AS `EsManejoC`,\n  `g_empresa`.`EsPlaboratorio`           AS `Laboratorio`,\n  `g_empresa`.`GRetencion`               AS `GRetencion`,\n  `g_empresa`.`Eps`                      AS `EsEps`,\n  `g_empresa`.`VCompraP`                 AS `VCompraP`,\n  `g_empresa`.`UFMovimientoC`            AS `FUMovimiento`,\n  `g_empresa`.`ActivoC`                  AS `ActivoC`,\n  `g_empresa`.`Estado`                   AS `Estado`,\n  `g_empresa`.`EsMInventario`            AS `EsMInventario`,\n  `g_empresa`.`TipoPersona`              AS `TipoPersona`,\n  `g_empresa`.`FacTInterna`              AS `FacTInterna`,\n  `g_empresa`.`Fecha_Ingreso`            AS `Fecha_Ingreso`,\n  `g_empresa`.`EsNomina`                 AS `EsNomina`,\n  `cc_tipo_clasificacion_tercero`.`Nbre` AS `Clasificacion`,\n  IF(`g_empresa`.`Id_TipoIdentificacion` = _latin1'NI',`g_empresa`.`Nbre`,CONCAT(`g_empresa`.`Apellido1`,_latin1' ',`g_empresa`.`Apellido2`,_latin1' ',`g_empresa`.`Nombre1`,_latin1' ',`g_empresa`.`Nombre2`)) AS `RazonSocialCompleta`,\n  IF(`g_empresa`.`Dig_Verificacion` = _latin1'',CONCAT(`g_empresa`.`Id_TipoIdentificacion`,_latin1' ',`g_empresa`.`No_identificacion`),CONCAT(IF(`g_empresa`.`Id_TipoIdentificacion` = _latin1'NI',_latin1'NIT',`g_empresa`.`Id_TipoIdentificacion`),_latin1' ',`g_empresa`.`No_identificacion`,_latin1'-',`g_empresa`.`Dig_Verificacion`)) AS `TDCompleto`,\n  IF(`g_empresa`.`Dig_Verificacion` = _latin1'',CONCAT(`g_empresa`.`Id_TipoIdentificacion`,_latin1' ',`g_empresa`.`No_identificacion`),CONCAT(`g_empresa`.`No_identificacion`,_latin1'-',`g_empresa`.`Dig_Verificacion`)) AS `TDCompleto1`,\n  IF(`g_empresa`.`Dig_Verificacion` = _latin1'',`g_empresa`.`No_identificacion`,CONCAT(`g_empresa`.`No_identificacion`,_latin1'-',`g_empresa`.`Dig_Verificacion`)) AS `TDCompleto2`\nFROM ((((`g_empresa`\n      JOIN `g_municipio`\n        ON (`g_empresa`.`Id_Municipio` = `g_municipio`.`Id`))\n     JOIN `g_departamento`\n       ON (`g_municipio`.`Id_Dpto` = `g_departamento`.`Id`))\n    JOIN `g_tipoidentificacion`\n      ON (`g_tipoidentificacion`.`Id` = `g_empresa`.`Id_TipoIdentificacion`))\n   JOIN `cc_tipo_clasificacion_tercero`\n     ON (`cc_tipo_clasificacion_tercero`.`Id` = `g_empresa`.`Id_ClasificacionT`))\nORDER BY `g_empresa`.`Nbre`\n\n)\n\n, set_actual AS (\nSELECT   pp_movimiento.id,\n\tpp_movimiento.IdDisponibilidad,\n\tpp_movimiento.`IdCompromiso`,\n       pp_movimiento.`IdObligacion`,\t\n       pp_movimiento.`NoDocumento`,\t\n    DATE_FORMAT(`pp_movimiento`.`FechaD`,'%d-%m-%Y') AS Fecha\t\n    , DATE_FORMAT(`pp_movimiento`.`FechaD`,'%d') AS Dia\n    , DATE_FORMAT(`pp_movimiento`.`FechaD`,'%m') AS Mes\n    , IF(`pp_movimiento`.`NoConcecutivo`=0,pp_detalle_movimiento.`Id`,`pp_movimiento`.`NoConcecutivo`) AS `Numero`\n    , IFNULL(`pp_tipo_documentos`.`Prefijo`,'') AS `Clase`\n    , pp_tipo_documentos.`Id_ClaseDoc`\n    , IF(pp_detalle_movimiento.`Tipo`=0,'2','1') AS Signo\n    , pp_detalle_movimiento.`Valor`\n    , `pp_movimiento`.`DatoResolucion` AS TipoDocSoporte\n    , `pp_movimiento`.`DatoResolucion` AS NumeroDocSoporte\n    , IF(cc_tercero_w.`Id_TipoIdentificacion`='CC',cc_tercero_w.`No_identificacion`,CONCAT(cc_tercero_w.`No_identificacion`,IF(cc_tercero_w.`Dig_Verificacion`<>'','-',''), cc_tercero_w.`Dig_Verificacion`)) identificacion\n    , cc_tercero_w.`RazonSocialCompleta`\n    , pp_detalle_movimiento.`Id_Rubro`\n    ,pp_movimiento.`Observacion`\n    \n  FROM\n    `pp_detalle_movimiento`\n    INNER JOIN `pp_movimiento` \n        ON (`pp_detalle_movimiento`.`Id_Movimiento` = `pp_movimiento`.`Id`)\n    INNER JOIN `pp_tipo_documentos` \n        ON (`pp_movimiento`.`Id_TipoDoc` = `pp_tipo_documentos`.`Id`)\n    INNER JOIN cc_tercero_w \n        ON (`pp_detalle_movimiento`.`Id_Tercero` = cc_tercero_w.`Id`)\nWHERE (`pp_tipo_documentos`.`Id_ClaseDoc` IN(4,5,6,12,13,14,15)     AND `pp_detalle_movimiento`.`Estado` =1 AND pp_movimiento.`Id_Periodo`=" + idPeriodo + " AND pp_detalle_movimiento.idEncabezado='" + idEncabezado + "')\nORDER BY `pp_tipo_documentos`.`Id_ClaseDoc` ASC,`pp_movimiento`.`FechaD` DESC\n)\n\n, set_compromiso AS (\nSELECT * FROM set_actual\nWHERE Id_ClaseDoc IN(4,12,13) \n)\n\n, set_obligacion AS (\nSELECT * FROM set_actual\nWHERE Id_ClaseDoc IN(5,14,15) \n)\n\n, set_pagos AS (\nSELECT * FROM set_actual\nWHERE Id_ClaseDoc IN(6) )\n\n\n,set_datos_actual AS (\nSELECT c.*, IFNULL(o.valor,0) valor_obligacion, IFNULL(p.valor,0) valor_pago \nFROM set_compromiso c\nLEFT JOIN set_obligacion o\n ON c.id=o.IdCompromiso  AND c.Id_Rubro=o.Id_Rubro\n LEFT JOIN set_pagos p\n ON o.id=p.IdObligacion   AND o.Id_Rubro=p.Id_Rubro\n )\n\n,w_ips AS (SELECT\n  IF(`g_ips`.`Id_TipoIdentificacion` = _latin1'NI',_latin1'NIT',`g_ips`.`Id_TipoIdentificacion`) AS `TipoIdEmpresa`,\n  `g_ips`.`Identificacion`        AS `NIEmpresa`,\n  `g_ips`.`DigitoVerificacion`    AS `DVempresa`,\n  `g_ips`.`Nbre`                  AS `NEmpresa`,\n  `g_ips`.`Direccion`             AS `Direccion`,\n  `g_ips`.`Direccion2`            AS `Direccion2`,\n  `g_ips`.`Eslogan`               AS `Eslogan`,\n  `g_ips`.`Telefono`              AS `Telefono`,\n  `g_ips`.`Fax`                   AS `Fax`,\n  `g_ips`.`Correo`                AS `Correo`,\n  `g_ips`.`Web`                   AS `Web`,\n  `g_ips`.`Administrador`         AS `Administrador`,\n  `g_ips`.`UrlFA`                 AS `UrlFA`,\n  `g_ips`.`Gerente`               AS `Gerente`,\n  `g_ips`.`UrlFG`                 AS `UrlFG`,\n  `g_ips`.`Presidente`            AS `Presidente`,\n  `g_ips`.`UrlFV`                 AS `UrlFV`,\n  `g_ips`.`Contadora`             AS `Contadora`,\n  `g_ips`.`UrlCd`                 AS `UrlCd`,\n  SUBSTR(`g_municipio`.`Id`,3,4)  AS `CodMunicipio`,\n  `g_municipio`.`Nbre`            AS `NMunicipio`,\n  `g_departamento`.`Id`           AS `CodDepartamento`,\n  `g_departamento`.`Nbre`         AS `NDepartamento`,\n  `g_departamento`.`CodPais`      AS `CodPais`,\n  `g_ips`.`TopeCompraA`           AS `TopeCompraA`,\n  `g_ips`.`TopeCompraG`           AS `TopeCompraG`,\n  `g_ips`.`TopeCompraV`           AS `TopeCompraV`,\n  `g_ips`.`NotaAnticipos`         AS `NotaAnticipos`,\n  IF(`g_ips`.`UrlLogo` = '',NULL,`g_ips`.`UrlLogo`) AS `Logo`,\n  IF(`g_ips`.`UrlLogoC` = '',NULL,`g_ips`.`UrlLogoC`) AS `LogoC`,\n  `g_ips`.`PiePaginaCitas`        AS `PiePaginaCitas`,\n  `g_ips`.`PiePaginaCitas1`       AS `PiePaginaCitas1`,\n  IF(`g_ips`.`UrlLogoSuperS` = '',NULL,`g_ips`.`UrlLogoSuperS`) AS `UrlLogoSuperS`,\n  `g_ips`.`ResolucionDian`        AS `ResolucionDian`,\n  IF(`g_ips`.`DigitoVerificacion` = _latin1'',`g_ips`.`Identificacion`,CONCAT(`g_ips`.`Identificacion`,_latin1'-',`g_ips`.`DigitoVerificacion`)) AS `IdConcatenado`,\n  `g_ips`.`Id_TipoIdentificacion` AS `TipoIdNormal`,\n  `g_ips`.`CodigoOrganismo`       AS `CodigoOrganismo`,\n  `g_ips`.`PiePagina1`            AS `PiePagina1`,\n  `g_ips`.`PiePagina2`            AS `PiePagina2`,\n  `g_ips`.`Id`                    AS `Id`,\n  `g_ips`.`Id_gempresa`           AS `Id_gempresa`,\n  `g_ips`.`LCertificacionSoat`    AS `LCertificacionSoat`,\n  `g_ips`.`LOrdenSalida`          AS `LOrdenSalida`,\n  `g_ips`.`prefijoReportes`       AS `prefijoReportes`\nFROM ((`g_ips`\n    JOIN `g_municipio`\n      ON (`g_ips`.`Id_Municipio` = `g_municipio`.`Id`))\n   JOIN `g_departamento`\n     ON (`g_municipio`.`Id_Dpto` = `g_departamento`.`Id`)))\n\n\nSELECT * FROM  w_ips, set_datos_actual rec\nINNER JOIN rubros_definitivos pres\nON rec.Id_Rubro=pres.Id  \nORDER BY rec.Id_Rubro";
        return sql;
    }

    @Override // com.genoma.plus.dao.presupuesto.EjecucionPresupuestalDAO
    public boolean verificarExistenciaTabla(String control) {
        boolean existe = false;
        RowMapper mapper = new RowMapper() { // from class: com.genoma.plus.dao.impl.presupuesto.EjecucionPresupuestalDAOImpl.4
            public Object mapRow(ResultSet rs, int rowNum) throws SQLException {
                Object[] fila = {rs.getString(1)};
                return fila;
            }
        };
        String sql = "SHOW TABLES LIKE 'tmp_rubros_nuevo_formato_" + control + "'";
        List<Object[]> list = this.jdbcTemplate.query(sql, mapper);
        if (list.size() > 0) {
            existe = true;
        }
        return existe;
    }

    @Override // com.genoma.plus.dao.presupuesto.EjecucionPresupuestalDAO
    public String queryEjecucionNeuva(String control, String idPeriodo, String idEncabezado) {
        String sql = "CREATE TABLE tmp_rubros_nuevo_formato_" + control + " AS \nWITH \nset_datos AS (SELECT\n\tpp_clase_documento.Id AS idClaseDocumento,\n\tpp_clase_documento.Nbre AS nombreClaseDocumento,\n\tpp_rubros.Id AS idRubro,\n\tpp_rubros.Nbre AS nombreRubro,\n\tpp_detalle_movimiento.idRubrosCpc AS idCpc,\n\tpp_rubros_cpc.codigo AS codigoCpc,\n\tpp_rubros_cpc.nombre AS nombreCpc,\n\tpp_detalle_movimiento.idRubrosFunteFinanciacion AS idFuenteFinanciacion,\n\tpp_rubros_fuente_financiacion.codigo AS codigoFuenteFinanciacion,\n\tpp_rubros_fuente_financiacion.nombre AS nombreFuenteFinanciacion,\n\tpp_detalle_movimiento.idRubrosCentroCostos AS idRubroCentroCosto,\n     pp_rubros_centrocostos.nombre AS nombreCentroCosto,\n     pp_detalle_movimiento.idTopoVigencia AS idTipoVigencia,\n     pp_tipo_vigencia.Nombre AS nombreVigencia,\n\tpp_rubros.TipoRubro,\n\tpp_detalle_movimiento.Tipo,\n\tpp_movimiento.Id_Periodo,\n\tSUM(pp_detalle_movimiento.Valor) Valor,\n\t@Periodo_Act Periodo_Act\nFROM\n\t(SELECT @Periodo_Act :='" + idPeriodo + "') p,\n\tpp_movimiento\nINNER JOIN pp_periodo                     ON  pp_movimiento.Id_Periodo = pp_periodo.Id\nINNER JOIN pp_detalle_movimiento          ON  pp_detalle_movimiento.Id_Movimiento = pp_movimiento.Id\nINNER JOIN pp_tipo_documentos             ON  pp_movimiento.Id_TipoDoc = pp_tipo_documentos.Id\nINNER JOIN pp_rubros                      ON  pp_detalle_movimiento.Id_Rubro = pp_rubros.Id\tAND pp_rubros.idEncabezadoRubro = pp_detalle_movimiento.idEncabezado\nINNER JOIN pp_rubros_fuente_financiacion  ON  pp_detalle_movimiento.idRubrosFunteFinanciacion = pp_rubros_fuente_financiacion.id\nINNER JOIN pp_rubros_cpc                  ON  pp_detalle_movimiento.idRubrosCpc = pp_rubros_cpc.id\nINNER JOIN pp_rubros_centrocostos         ON  pp_detalle_movimiento.idRubrosCentroCostos = pp_rubros_centrocostos.id\nINNER JOIN pp_clase_documento             ON  pp_tipo_documentos.Id_ClaseDoc = pp_clase_documento.Id\nINNER JOIN pp_tipo_vigencia               ON  pp_detalle_movimiento.idTopoVigencia = pp_tipo_vigencia.Id\nWHERE pp_detalle_movimiento.idEncabezado ='" + idEncabezado + "' AND pp_periodo.Id IN \n(SELECT pant.Id\n\tFROM pp_periodo pant,\n\t\t(SELECT\n\t\t\tId,\n\t\t\tFechaI,\n\t\t\tFechaF\n\t\tFROM pp_periodo\n\t\tWHERE Id ='" + idPeriodo + "') pact\n\tWHERE (DATE_FORMAT(pant.FechaI, '%Y') = DATE_FORMAT(pact.FechaI, '%Y') AND pant.FechaF <= pact.FechaI)\n\tOR pact.Id = pant.id)\n\tAND pp_movimiento.Id_MotivoAnulacion = 1\n\tAND pp_detalle_movimiento.Estado = 1\nGROUP BY\n\tpp_clase_documento.Id,\n\tpp_clase_documento.Nbre,\n\tpp_rubros.Id,\n\tpp_detalle_movimiento.Tipo,\n\tpp_detalle_movimiento.idRubrosCpc,\n\tpp_detalle_movimiento.idRubrosFunteFinanciacion,\n\tpp_detalle_movimiento.idRubrosCentroCostos,\n\tpp_movimiento.Id_Periodo),\ndatos_campos AS (SELECT\n\tidRubro,\n\tnombreRubro,\n\tidCpc,\n\tcodigoCpc,\n\tnombreCpc,\n\tidFuenteFinanciacion,\n\tcodigoFuenteFinanciacion,\n\tnombreFuenteFinanciacion,\n\tidRubroCentroCosto,\n\tnombreCentroCosto,\n\tidTipoVigencia,\n\tnombreVigencia,\n\tTipoRubro,\n\tCASE\n\t\tWHEN idClaseDocumento = 1 \n        THEN Valor\n\t  END Presupuesto_Inicial,\n\tCASE\n\t\tWHEN idClaseDocumento = 8\n\t\tAND Tipo = 1 \n        THEN Valor\n\t  END Adicion_Presupuesto,\n\tCASE\n\t\tWHEN idClaseDocumento = 8\n\t\tAND Tipo = 0 \n        THEN Valor\n\t  END Reduccion_Presupuesto,\n\tCASE\n\t\tWHEN idClaseDocumento = 7\n\t\tAND Tipo = 0 \n        THEN Valor\n\t  END Traslados_Debitos,\n\tCASE\n\t\tWHEN idClaseDocumento = 7\n\t\tAND Tipo = 1 \n        THEN Valor\n\t  END Traslados_Creditos,\n\tCASE\n\t\tWHEN idClaseDocumento = 2\n\t\tAND Id_Periodo <> Periodo_Act \n        THEN Valor\n\t  END Reconocimiento_Anterior,\n\tCASE\n\t\tWHEN idClaseDocumento = 2\n\t\tAND Id_Periodo = Periodo_Act \n        THEN Valor\n\t  END Reconocimiento_Actual,\n\tCASE\n\t\tWHEN idClaseDocumento = 3\n\t\tAND Id_Periodo <> Periodo_Act \n        THEN Valor\n\t  END Recaudo_Anterior,\n\tCASE\n\t\tWHEN idClaseDocumento = 3\n\t\tAND Id_Periodo = Periodo_Act \n        THEN Valor\n\t  END Recaudo_Actual,\n\tCASE\n\t    WHEN idClaseDocumento IN (9, 10) AND Id_Periodo <> Periodo_Act \n        THEN Valor\n\t\tWHEN idClaseDocumento IN (11) AND Id_Periodo <> Periodo_Act \n        THEN Valor * (- 1)\n\t  END Disponibilidad_Anterior,\n\tCASE\n\t\tWHEN idClaseDocumento IN (9, 10) AND Id_Periodo = Periodo_Act \n        THEN Valor\n\t\tWHEN idClaseDocumento IN (11) AND Id_Periodo = Periodo_Act \n        THEN Valor * (- 1)\n\t  END Disponibilidad_Actual,\n\tCASE\n\t\tWHEN idClaseDocumento IN (4, 12) AND Id_Periodo <> Periodo_Act \n        THEN Valor\n\t\tWHEN idClaseDocumento IN (13) AND Id_Periodo <> Periodo_Act \n        THEN Valor * (- 1)\n\t  END Compromiso_Anterior,\n\tCASE\n\t\tWHEN idClaseDocumento IN (4, 12) AND Id_Periodo = Periodo_Act \n        THEN Valor\n\t\tWHEN idClaseDocumento IN (13) AND Id_Periodo = Periodo_Act \n        THEN Valor * (- 1)\n\t  END Compromiso_Actual,\n\tCASE\n\t\tWHEN idClaseDocumento IN (5, 14) AND Id_Periodo <> Periodo_Act \n        THEN Valor\n\t\tWHEN idClaseDocumento IN (15) AND Id_Periodo <> Periodo_Act \n        THEN Valor * (- 1)  \n      END Obligacion_Anterior,\n\tCASE\n\t\tWHEN idClaseDocumento IN (5, 14) AND Id_Periodo = Periodo_Act \n\t\tTHEN Valor\n\t\tWHEN idClaseDocumento IN (15) AND Id_Periodo = Periodo_Act \n\t\tTHEN Valor * (- 1)\n\t  END Obligacion_Actual,\n\tCASE\n\t\tWHEN idClaseDocumento = 6 AND Id_Periodo <> Periodo_Act \n        THEN Valor\n\t  END Pagos_Anterior,\n\tCASE\n\t\tWHEN idClaseDocumento = 6 AND Id_Periodo = Periodo_Act \n\t\tTHEN Valor\n\t  END Pagos_Actual,\n\tCASE\n\t\tWHEN idClaseDocumento = 13  \n        THEN Valor\n\t  END reintegroCompromiso,\n\tCASE\n\t\tWHEN idClaseDocumento = 11  \n        THEN Valor\n\t  END reintegroDisponibilidad\nFROM set_datos),\nsuma_rubros AS (SELECT \n\tidRubro,\n\tnombreRubro,\n\tidCpc,\n\tcodigoCpc,\n\tnombreCpc,\n\tidFuenteFinanciacion,\n\tcodigoFuenteFinanciacion,\n\tnombreFuenteFinanciacion,\n\tidRubroCentroCosto,\n\tnombreCentroCosto,\n\tidTipoVigencia,\n\tnombreVigencia,\n\tTipoRubro,\n\tSUM(IFNULL(Presupuesto_Inicial, 0)) Presupuesto_Inicial,\n\tSUM(IFNULL(Adicion_Presupuesto, 0)) Adicion_Presupuesto,\n\tSUM(IFNULL(Reduccion_Presupuesto, 0)) Reduccion_Presupuesto,\n\tSUM(IFNULL(Traslados_Debitos, 0)) Traslados_Debitos,\n\tSUM(IFNULL(Traslados_Creditos, 0)) Traslados_Creditos,\n\tSUM(IFNULL(Reconocimiento_Anterior, 0)) Reconocimiento_Anterior,\n\tSUM(IFNULL(Reconocimiento_Actual, 0)) Reconocimiento_Actual,\n\tSUM(IFNULL(Recaudo_Anterior, 0)) Recaudo_Anterior,\n\tSUM(IFNULL(Recaudo_Actual, 0)) Recaudo_Actual,\n\tSUM(IFNULL(Disponibilidad_Anterior, 0)) Disponibilidad_Anterior,\n\tSUM(IFNULL(Disponibilidad_Actual, 0)) Disponibilidad_Actual,\n\tSUM(IFNULL(Compromiso_Anterior, 0)) Compromiso_Anterior,\n\tSUM(IFNULL(Compromiso_Actual, 0)) Compromiso_Actual,\n\tSUM(IFNULL(Obligacion_Anterior, 0)) Obligacion_Anterior,\n\tSUM(IFNULL(Obligacion_Actual, 0)) Obligacion_Actual,\n\tSUM(IFNULL(Pagos_Anterior, 0)) Pagos_Anterior,\n\tSUM(IFNULL(Pagos_Actual, 0)) Pagos_Actual,\n\tSUM(IFNULL(reintegroCompromiso, 0)) Reintegro_Compromiso,\n\tSUM(IFNULL(reintegroDisponibilidad, 0)) Reintegro_Disponibilidad\nFROM\n\tdatos_campos\nGROUP BY\n\tidRubro,\n\tnombreRubro,\n\tidCpc,\n\tnombreCpc,\n\tidFuenteFinanciacion,\n\tnombreFuenteFinanciacion,\n\tidRubroCentroCosto,\n\tnombreCentroCosto,\n\tTipoRubro),\nset_campos_definitivos AS (SELECT\n\tidRubro,\n\tnombreRubro,\n\tidCpc,\n\tcodigoCpc,\n\tnombreCpc,\n\tidFuenteFinanciacion,\n\tcodigoFuenteFinanciacion,\n\tnombreFuenteFinanciacion,\n\tidRubroCentroCosto,\n\tnombreCentroCosto,\n\tidTipoVigencia,\n\tnombreVigencia,\n\tTipoRubro,\n\tPresupuesto_Inicial,\n\tAdicion_Presupuesto,\n\tReduccion_Presupuesto,\n\tTraslados_Debitos,\n\tTraslados_Creditos,\n\t(Presupuesto_Inicial + Adicion_Presupuesto - Reduccion_Presupuesto - Traslados_Debitos + Traslados_Creditos) Presupuesto_Definitivo,\n\tReconocimiento_Anterior,\n\tReconocimiento_Actual,\n\t(Reconocimiento_Anterior + Reconocimiento_Actual) Reconocimiento_Total,\n\tRecaudo_Anterior,\n\tRecaudo_Actual,\n\t(Recaudo_Anterior + Recaudo_Actual) Recaudo_Total,\n\t((Presupuesto_Inicial + Adicion_Presupuesto - Reduccion_Presupuesto - Traslados_Debitos + Traslados_Creditos) - (Reconocimiento_Anterior + Reconocimiento_Actual)) Saldo_por_Ejecutar,          \t\n\t((Reconocimiento_Anterior + Reconocimiento_Actual) - (Recaudo_Anterior + Recaudo_Actual)) Saldo_por_Recaudar,\n\tDisponibilidad_Anterior AS Certificado_Anterior,\n\tDisponibilidad_Actual AS Certificado_Actual,\n\t(Disponibilidad_Anterior + Disponibilidad_Actual) Total_Certificados,\n\tCompromiso_Anterior,\n\tCompromiso_Actual,\n\t(Compromiso_Anterior + Compromiso_Actual) Compromiso_Total,\n\tObligacion_Anterior,\n\tObligacion_Actual,\n\t(Obligacion_Anterior + Obligacion_Actual) Total_Obligaciones,\n\tPagos_Anterior,\n\tPagos_Actual,\n\t(Pagos_Anterior + Pagos_Actual) Total_Pagos,\n\t((Presupuesto_Inicial + Adicion_Presupuesto - Reduccion_Presupuesto - Traslados_Debitos + Traslados_Creditos) - (Disponibilidad_Anterior + Disponibilidad_Actual)) Saldo_Disponible,                 \t\n\t((Presupuesto_Inicial + Adicion_Presupuesto - Reduccion_Presupuesto - Traslados_Debitos + Traslados_Creditos) - (Compromiso_Anterior + Compromiso_Actual)) Sin_Comprometer,             \t\n\t((Compromiso_Anterior + Compromiso_Actual) - (Pagos_Anterior + Pagos_Actual)) Compromisos_por_Pagar,\n\t((Obligacion_Anterior + Obligacion_Actual) - (Pagos_Anterior + Pagos_Actual)) Cuentas_por_Pagar,\n\t((Disponibilidad_Anterior + Disponibilidad_Actual) - (Compromiso_Anterior + Compromiso_Actual)) Certificado_sin_Comprometer,\n\tReintegro_Compromiso,\n\tReintegro_Disponibilidad\nFROM suma_rubros),\nrubros_definitivos AS \n(SELECT\n\tr.Id AS codigoRubro,\n\tr.IdPadre AS codigoPadre,\n\tr.Nbre AS nombreRubro,\n\tIF(r.cod_alterno IS NULL OR r.cod_alterno = '', '', r.cod_alterno) AS codigoAlterno,\n\tr.TipoRubro,\n\tIF(r.ultnivel = 1, 'CAPTURA', 'AGREGACION') AS nivel,\n\tIF(codigoCpc IS NULL OR codigoCpc = '', '',codigoCpc) AS codigoCpc,\n\tIF(nombreCpc IS NULL OR nombreCpc = '', '', nombreCpc) AS nombreCpc,\n\tIF(codigoFuenteFinanciacion IS NULL OR codigoFuenteFinanciacion = '', '', codigoFuenteFinanciacion) AS codigoFuenteFinanciacion,\n\tIF(nombreFuenteFinanciacion IS NULL OR nombreFuenteFinanciacion = '', '', nombreFuenteFinanciacion) AS nombreFuenteFinanciacion,\n\tIF(nombreCentroCosto IS NULL OR nombreCentroCosto = '', '', nombreCentroCosto) AS nombreCentroCosto,\n\tIF(nombreVigencia IS NULL OR nombreVigencia = '', '', nombreVigencia) AS nombreVigencia,\n\tIFNULL(Presupuesto_Inicial, 0) Presupuesto_Inicial,\n\tIFNULL(Adicion_Presupuesto, 0) Adicion_Presupuesto,\n\tIFNULL(Reduccion_Presupuesto, 0) Reduccion_Presupuesto,\n\tIFNULL(Traslados_Debitos, 0) Traslados_Debitos,\n\tIFNULL(Traslados_Creditos, 0) Traslados_Creditos,\n\tIFNULL(Presupuesto_Definitivo, 0) Presupuesto_Definitivo,\n\tIFNULL(Reconocimiento_Anterior, 0) Reconocimiento_Anterior,\n\tIFNULL(Reconocimiento_Actual, 0) Reconocimiento_Actual,\n\tIFNULL(Reconocimiento_Total, 0) Reconocimiento_Total,\n\tIFNULL(Recaudo_Anterior, 0) Recaudo_Anterior,\n\tIFNULL(Recaudo_Actual, 0) Recaudo_Actual,\n\tIFNULL(Recaudo_Total, 0) Recaudo_Total,\n\tIFNULL(Saldo_por_Ejecutar, 0) Saldo_por_Ejecutar,\n\tIFNULL(Saldo_por_Recaudar, 0) Saldo_por_Recaudar,\n\tIFNULL(Certificado_Anterior, 0) Certificado_Anterior,\n\tIFNULL(Certificado_Actual, 0) Certificado_Actual,\n\tIFNULL(Reintegro_Disponibilidad, 0) ReintegroCertificados,\n\tIFNULL(Total_Certificados, 0) Total_Certificados,\n\tIFNULL(Compromiso_Anterior, 0) Compromiso_Anterior,\n\tIFNULL(Compromiso_Actual, 0) Compromiso_Actual,\n\tIFNULL(Reintegro_Compromiso, 0) ReintegroCompromiso,\n\tIFNULL(Compromiso_Total, 0) Compromiso_Total,\n\tIFNULL(Obligacion_Anterior, 0) Obligacion_Anterior,\n\tIFNULL(Obligacion_Actual, 0) Obligacion_Actual,\n\t0 ReintegroObligacion,\n\tIFNULL(Total_Obligaciones, 0) Total_Obligaciones,\n\tIFNULL(Pagos_Anterior, 0) Pagos_Anterior,\n\tIFNULL(Pagos_Actual, 0) Pagos_Actual,\n\tIFNULL(Total_Pagos, 0) Total_Pagos,\n\tIFNULL(Saldo_Disponible, 0) Saldo_Disponible,\n\tIFNULL(Sin_Comprometer, 0) Sin_Comprometer,\n\tIFNULL(Compromisos_por_Pagar, 0) Compromisos_por_Pagar,\n\tIFNULL(Cuentas_por_Pagar, 0) Cuentas_por_Pagar,\n\tIFNULL(Certificado_sin_Comprometer, 0) Certificado_sin_Comprometer,\n\t0 CompromisossinObligacion\nFROM\n\tpp_rubros r\nLEFT JOIN set_campos_definitivos AS P ON P.idRubro = r.id\nWHERE r.idEncabezadoRubro = '" + idEncabezado + "'\nORDER BY\n\tr.orden ASC,\n\tnombreCpc,\n\tnombreFuenteFinanciacion,\n\tnombreCentroCosto) \nSELECT * FROM rubros_definitivos;";
        this.jdbcTemplate.execute(sql);
        return sql;
    }

